static char sx__str2414[]="data $str_w_mode = { b \"w\", b 0 }\ndata $str_r_mode = { b \"r\", b 0 }\ndata $sx_stdin_ptr = { l 0 }\ndata $sx_stdout_ptr = { l 0 }\ndata $sx_stderr_ptr = { l 0 }\n\nfunction l $sx_stdout() {\n@start\n    %p =l loadl $sx_stdout_ptr\n    %c =w cnel %p, 0\n    jnz %c, @done, @init\n@init\n    %r =l call $fdopen(w 1, l $str_w_mode)\n    storel %r, $sx_stdout_ptr\n    ret %r\n@done\n    ret %p\n}\nfunction l $sx_stderr() {\n@start\n    %p =l loadl $sx_stderr_ptr\n    %c =w cnel %p, 0\n    jnz %c, @done, @init\n@init\n    %r =l call $fdopen(w 2, l $str_w_mode)\n    storel %r, $sx_stderr_ptr\n    ret %r\n@done\n    ret %p\n}\nfunction l $sx_stdin() {\n@start\n    %p =l loadl $sx_stdin_ptr\n    %c =w cnel %p, 0\n    jnz %c, @done, @init\n@init\n    %r =l call $fdopen(w 0, l $str_r_mode)\n    storel %r, $sx_stdin_ptr\n    ret %r\n@done\n    ret %p\n}\n\ndata $sx_argc_store = { l 0 }\ndata $sx_argv_store = { l 0 }\n\nfunction l $sx_get_args() {\n@start\n    %argc =l loadl $sx_argc_store\n    %argv =l loadl $sx_argv_store\n    %hdr =l call $malloc(l 24)\n    %cap =l mul %argc, 8\n    %buf =l call $malloc(l %cap)\n    storel %buf, %hdr\n    %len_slot =l add %hdr, 8\n    storel 0, %len_slot\n    %cap_slot =l add %hdr, 16\n    storel %argc, %cap_slot\n    %i =l copy 0\n@args_loop\n    %done =w csgel %i, %argc\n    jnz %done, @args_done, @args_body\n@args_body\n    %off =l mul %i, 8\n    %slot =l add %argv, %off\n    %str =l loadl %slot\n    %cur_len =l loadl %len_slot\n    %boff =l mul %cur_len, 8\n    %bslot =l add %buf, %boff\n    storel %str, %bslot\n    %new_len =l add %cur_len, 1\n    storel %new_len, %len_slot\n    %i =l add %i, 1\n    jmp @args_loop\n@args_done\n    ret %hdr\n}\n\nfunction l $__sx_get_args() {\n@start\n    %r =l call $sx_get_args()\n    ret %r\n}\n\nfunction w $os__exit(w %code) {\n@start\n    call $exit(w %code)\n    ret 0\n}";
